    pub fn odd_even_list(head: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
        let mut head = head;
        if head.is_none() {
            return None;
        }
        let mut odd = head.as_mut().unwrap();
        let mut even = odd.next.as_mut().map(|n| n.clone());
        let mut even_head = even.clone();
        while let Some(ref mut e) = even {
            if e.next.is_none() {
                break;
            }
            let odd_next = e.next.take().unwrap();
            odd.next = Some(odd_next.clone());
            odd = odd.next.as_mut().unwrap();
            let even_next = odd.next.take();
            e.next = even_next;
            even = e.next.as_mut().map(|n| n.clone());
        }
        odd.next = even_head;
